#include "aht20.h"
#include <Wire.h>
#include <Adafruit_AHTX0.h>
static Adafruit_AHTX0 aht;
static float _t=0,_h=0;
static unsigned long _last=0;
void aht20_setup(){Wire.begin();if(!aht.begin()){Serial.println("[aht20] Fail!");return;}Serial.println("[aht20] OK");}
void aht20_loop(){if(millis()-_last<2000)return;_last=millis();sensors_event_t h,t;aht.getEvent(&h,&t);_t=t.temperature;_h=h.relative_humidity;}
float aht20_get_temperature(){return _t;}
float aht20_get_humidity(){return _h;}
